#include <iostream>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n;
    cin >> n;

    long long fact = 1;
    for (int i = 1; ; i++) {
        if (fact == n) {
            cout << i << '\n';
            return 0;
        }
        if (fact > n) {
            cout << "No\n";
            return 0;
        }
        fact *= (i + 1);
    }
}
